let preguntasActuales = [];
let indiceActual = 0;
let racha = 0;
let categoriaSeleccionada = 'todas';
let dificultadSeleccionada = 'todas';
let respuestaCorrecta = 'a';

document.querySelectorAll('[data-categoria]').forEach(btn => {
    btn.addEventListener('click', () => {
        document.querySelectorAll('[data-categoria]').forEach(b => b.classList.remove('activo'));
        btn.classList.add('activo');
        categoriaSeleccionada = btn.dataset.categoria;
    });
});

document.querySelectorAll('[data-dificultad]').forEach(btn => {
    btn.addEventListener('click', () => {
        document.querySelectorAll('[data-dificultad]').forEach(b => b.classList.remove('activo'));
        btn.classList.add('activo');
        dificultadSeleccionada = btn.dataset.dificultad;
    });
});

document.getElementById('btn-jugar').addEventListener('click', () => {
    let filtradas = preguntas;
    if (categoriaSeleccionada !== 'todas') {
        filtradas = filtradas.filter(p => p.categoria === categoriaSeleccionada);
    }
    if (dificultadSeleccionada !== 'todas') {
        filtradas = filtradas.filter(p => p.dificultad === dificultadSeleccionada);
    }
    if (filtradas.length === 0) {
        alert('No hay preguntas para esa combinación. Probá otra.');
        return;
    }
    preguntasActuales = mezclar([...filtradas]);
    indiceActual = 0;
    racha = 0;
    mostrarPantalla('pantalla-juego');
    mostrarPregunta();
});

document.getElementById('btn-siguiente').addEventListener('click', () => {
    indiceActual++;
    if (indiceActual >= preguntasActuales.length) {
        preguntasActuales = mezclar([...preguntasActuales]);
        indiceActual = 0;
    }
    mostrarPantalla('pantalla-juego');
    mostrarPregunta();
});

document.getElementById('btn-volver').addEventListener('click', () => {
    racha = 0;
    mostrarPantalla('pantalla-inicio');
});

function mostrarPregunta() {
    const p = preguntasActuales[indiceActual];
    const invertir = Math.random() < 0.5;

    document.getElementById('pregunta-texto').textContent = p.pregunta;
    document.getElementById('opcion-a').textContent = invertir ? p.opcion_b : p.opcion_a;
    document.getElementById('opcion-b').textContent = invertir ? p.opcion_a : p.opcion_b;
    respuestaCorrecta = invertir ? (p.correcta === 'a' ? 'b' : 'a') : p.correcta;

    document.getElementById('info-categoria').textContent =
        capitalizar(p.categoria) + ' · ' + capitalizar(p.dificultad);
    document.getElementById('racha-valor').textContent = racha;

    const btnA = document.getElementById('opcion-a');
    const btnB = document.getElementById('opcion-b');
    btnA.className = 'btn-opcion';
    btnB.className = 'btn-opcion';
    btnA.disabled = false;
    btnB.disabled = false;
    btnA.onclick = () => responder('a');
    btnB.onclick = () => responder('b');
}

function responder(elegida) {
    const p = preguntasActuales[indiceActual];
    const esCorrecta = elegida === respuestaCorrecta;

    document.getElementById('opcion-a').disabled = true;
    document.getElementById('opcion-b').disabled = true;

    if (esCorrecta) {
        racha++;
        document.getElementById('opcion-' + elegida).classList.add('correcto');
    } else {
        racha = 0;
        document.getElementById('opcion-' + elegida).classList.add('incorrecto');
        document.getElementById('opcion-' + respuestaCorrecta).classList.add('correcto');
    }

    setTimeout(() => mostrarResultado(esCorrecta, p), 900);
}

function mostrarResultado(esCorrecta, p) {
    document.getElementById('resultado-icono').textContent = esCorrecta ? '✅' : '❌';
    const titulo = document.getElementById('resultado-titulo');
    titulo.textContent = esCorrecta ? '¡Correcto!' : 'Incorrecto';
    titulo.className = esCorrecta ? 'correcto' : 'incorrecto';
    document.getElementById('resultado-explicacion').textContent = p.explicacion;
    document.getElementById('racha-resultado-valor').textContent = racha;
    mostrarPantalla('pantalla-resultado');
}

function mostrarPantalla(id) {
    document.querySelectorAll('.pantalla').forEach(p => p.classList.remove('activa'));
    document.getElementById(id).classList.add('activa');
}

function mezclar(arr) {
    for (let i = arr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
}

function capitalizar(str) {
    return str.charAt(0).toUpperCase() + str.slice(1);
}
